import { getLocale, getTranslations } from "next-intl/server";
import { AppShell } from "@/components/app-shell";
import { ProfileLanguageForm } from "@/components/profile-language-form";
import { normalizeLocale, type AppLocale } from "@/i18n/locales";
import { getAuthContext } from "@/lib/firebase/auth";
import { usersRepository } from "@/lib/repositories/users-repository";

export default async function ProfilePage() {
  const t = await getTranslations("Profile");
  const common = await getTranslations("Common");
  const locale = normalizeLocale(await getLocale()) as AppLocale;
  const auth = await getAuthContext();
  const profile = auth?.userId ? await usersRepository.getUserProfile(auth.userId).catch(() => null) : null;
  const currentLocale = normalizeLocale(profile?.locale) ?? locale;

  return (
    <AppShell section="profile">
      <div className="content-stack space-y-6">
        <section className="app-card">
          <h2 className="mb-2 font-semibold">{t("account")}</h2>
          <p className="text-sm muted">{t("user", { userId: auth?.userId || "nao autenticado" })}</p>
          <p className="text-sm muted">{t("email", { email: auth?.email || common("notAvailable") })}</p>
          <p className="text-sm muted">{t("workspace", { workspaceId: auth?.workspaceId || common("notAvailable") })}</p>
        </section>
        <section className="app-card">
          <h2 className="mb-2 font-semibold">{t("languageTitle")}</h2>
          <p className="mb-3 text-sm muted">{t("languageDescription")}</p>
          <ProfileLanguageForm currentLocale={currentLocale} />
        </section>
        <section className="app-card">
          <h2 className="mb-2 font-semibold">{t("agentsTitle")}</h2>
          <p className="text-sm muted">{t("agentsDescription")}</p>
        </section>
      </div>
    </AppShell>
  );
}
